"use client";

import { useState, useEffect, useRef } from "react";
import { X, ArrowUpRight, CheckCircle2 } from "lucide-react";

interface Props {
  open: boolean;
  onClose: () => void;
}

const modules = ["Finance & GST", "HRM & Payroll", "CRM & Sales", "Inventory", "Analytics", "Mobile Apps"];

export default function DemoModal({ open, onClose }: Props) {
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);
  const overlayRef = useRef<HTMLDivElement>(null);

  // Close on Escape
  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [open, onClose]);

  // Prevent body scroll
  useEffect(() => {
    document.body.style.overflow = open ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [open]);

  function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => { setLoading(false); setSubmitted(true); }, 1200);
  }

  function handleClose() {
    onClose();
    setTimeout(() => setSubmitted(false), 300);
  }

  if (!open) return null;

  return (
    <div
      ref={overlayRef}
      className="fixed inset-0 z-[999] flex items-center justify-center p-4"
      style={{ background: "rgba(10,15,25,0.72)", backdropFilter: "blur(4px)" }}
      onClick={(e) => { if (e.target === overlayRef.current) handleClose(); }}
    >
      <div
        className="relative w-full max-w-lg rounded-2xl overflow-hidden"
        style={{ background: "#fff", boxShadow: "0 24px 80px rgba(0,0,0,0.22)" }}
      >
        {/* Header */}
        <div
          className="px-7 py-5 flex items-start justify-between"
          style={{ background: "linear-gradient(135deg, #0d1a2e 0%, #1a2332 100%)" }}
        >
          <div>
            <h3 className="font-bold text-lg" style={{ color: "#fff" }}>Request a Demo</h3>
            <p className="text-sm mt-0.5" style={{ color: "rgba(255,255,255,0.55)" }}>
              We will set up a personalised walkthrough for your business.
            </p>
          </div>
          <button
            onClick={handleClose}
            className="w-8 h-8 rounded-full flex items-center justify-center transition-colors hover:bg-white/10"
            style={{ color: "rgba(255,255,255,0.6)" }}
            aria-label="Close"
          >
            <X size={16} />
          </button>
        </div>

        {/* Body */}
        <div className="px-7 py-6">
          {submitted ? (
            <div className="flex flex-col items-center text-center py-6 gap-4">
              <div
                className="w-14 h-14 rounded-full flex items-center justify-center"
                style={{ background: "rgba(5,150,105,0.1)" }}
              >
                <CheckCircle2 size={28} style={{ color: "#059669" }} />
              </div>
              <div>
                <h4 className="font-bold text-lg mb-1" style={{ color: "var(--dark)" }}>Request received!</h4>
                <p className="text-sm leading-relaxed" style={{ color: "var(--text)" }}>
                  Our team will reach out within one business day to schedule your personalised demo.
                </p>
              </div>
              <button
                onClick={handleClose}
                className="mt-2 px-6 py-2.5 rounded-xl text-sm font-semibold transition-all duration-200 hover:opacity-90"
                style={{ background: "linear-gradient(135deg, var(--primary) 0%, #7c3aed 100%)", color: "#fff" }}
              >
                Done
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="flex flex-col gap-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="flex flex-col gap-1.5">
                  <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Full Name <span style={{ color: "#ef4444" }}>*</span></label>
                  <input
                    required
                    type="text"
                    placeholder="Ravi Kumar"
                    className="px-3.5 py-2.5 rounded-xl text-sm outline-none transition-all"
                    style={{ border: "1px solid var(--border-light)", color: "var(--dark)", background: "var(--gray-bg)" }}
                    onFocus={(e) => (e.currentTarget.style.borderColor = "var(--primary)")}
                    onBlur={(e) => (e.currentTarget.style.borderColor = "var(--border-light)")}
                  />
                </div>
                <div className="flex flex-col gap-1.5">
                  <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Company Name <span style={{ color: "#ef4444" }}>*</span></label>
                  <input
                    required
                    type="text"
                    placeholder="Your Business"
                    className="px-3.5 py-2.5 rounded-xl text-sm outline-none transition-all"
                    style={{ border: "1px solid var(--border-light)", color: "var(--dark)", background: "var(--gray-bg)" }}
                    onFocus={(e) => (e.currentTarget.style.borderColor = "var(--primary)")}
                    onBlur={(e) => (e.currentTarget.style.borderColor = "var(--border-light)")}
                  />
                </div>
              </div>

              <div className="flex flex-col gap-1.5">
                <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Work Email <span style={{ color: "#ef4444" }}>*</span></label>
                <input
                  required
                  type="email"
                  placeholder="ravi@yourbusiness.com"
                  className="px-3.5 py-2.5 rounded-xl text-sm outline-none transition-all"
                  style={{ border: "1px solid var(--border-light)", color: "var(--dark)", background: "var(--gray-bg)" }}
                  onFocus={(e) => (e.currentTarget.style.borderColor = "var(--primary)")}
                  onBlur={(e) => (e.currentTarget.style.borderColor = "var(--border-light)")}
                />
              </div>

              <div className="flex flex-col gap-1.5">
                <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Phone Number <span style={{ color: "#ef4444" }}>*</span></label>
                <input
                  required
                  type="tel"
                  placeholder="+91 98765 43210"
                  className="px-3.5 py-2.5 rounded-xl text-sm outline-none transition-all"
                  style={{ border: "1px solid var(--border-light)", color: "var(--dark)", background: "var(--gray-bg)" }}
                  onFocus={(e) => (e.currentTarget.style.borderColor = "var(--primary)")}
                  onBlur={(e) => (e.currentTarget.style.borderColor = "var(--border-light)")}
                />
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Modules of Interest</label>
                <div className="flex flex-wrap gap-2">
                  {modules.map((m) => (
                    <label key={m} className="flex items-center gap-1.5 cursor-pointer">
                      <input type="checkbox" className="rounded" style={{ accentColor: "var(--primary)" }} />
                      <span className="text-xs" style={{ color: "var(--text)" }}>{m}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="flex flex-col gap-1.5">
                <label className="text-xs font-semibold" style={{ color: "var(--dark)" }}>Team Size</label>
                <select
                  className="px-3.5 py-2.5 rounded-xl text-sm outline-none transition-all"
                  style={{ border: "1px solid var(--border-light)", color: "var(--text)", background: "var(--gray-bg)" }}
                  onFocus={(e) => (e.currentTarget.style.borderColor = "var(--primary)")}
                  onBlur={(e) => (e.currentTarget.style.borderColor = "var(--border-light)")}
                >
                  <option value="">Select team size</option>
                  <option>1 – 10 employees</option>
                  <option>11 – 50 employees</option>
                  <option>51 – 200 employees</option>
                  <option>200+ employees</option>
                </select>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="mt-1 inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl text-sm font-semibold transition-all duration-200 hover:opacity-90 disabled:opacity-70"
                style={{ background: "linear-gradient(135deg, var(--primary) 0%, #7c3aed 100%)", color: "#fff" }}
              >
                {loading ? "Sending…" : <><span>Request Demo</span><ArrowUpRight size={14} /></>}
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
