"use client";

import { useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { Phone, MapPin } from "lucide-react";
import DemoModal from "@/components/DemoModal";

const NAV = [
  { label: "Modules",   href: "/features" },
  { label: "Resources", href: "/resources" },
  { label: "About Us",  href: "/about" },
  { label: "Careers",   href: "/careers" },
  { label: "Contact",   href: "/contact" },
];

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [demoOpen, setDemoOpen] = useState(false);
  const pathname = usePathname();

  return (
    <>
    <DemoModal open={demoOpen} onClose={() => setDemoOpen(false)} />
    <header className="fixed top-0 left-0 w-full z-50">
      {/* ── Top info bar ── */}
      <div
        className="hidden sm:block"
        style={{ background: "var(--dark-alt)", borderBottom: "1px solid rgba(255,255,255,0.08)" }}
      >
        <div className="container-xl flex items-center justify-between h-9">
          <div
            className="flex items-center gap-1.5 text-[11px]"
            style={{ color: "rgba(255,255,255,0.55)" }}
          >
            <Phone size={10} strokeWidth={2} className="shrink-0" />
            <span>+91 73732 88133</span>
          </div>
          <div
            className="flex items-center gap-1.5 text-[11px]"
            style={{ color: "rgba(255,255,255,0.55)" }}
          >
            <MapPin size={10} strokeWidth={2} className="shrink-0" />
            <span>Chennai, Tamil Nadu, India</span>
          </div>
        </div>
      </div>

      {/* ── Main nav bar ── */}
      <div style={{ background: "var(--dark)", boxShadow: "0 1px 0 rgba(255,255,255,0.06)" }}>
        <div className="container-xl flex items-center justify-between h-[64px]">
          {/* Logo */}
          <Link href="/" className="flex items-center gap-2 shrink-0">
            <SyncCoreLogo />
          </Link>

          {/* Desktop nav */}
          <nav className="hidden lg:flex items-center gap-7">
            {NAV.map((link) => (
              <Link
                key={link.label}
                href={link.href}
                className="text-sm font-medium transition-colors"
                style={{
                  color: pathname === link.href ? "var(--primary)" : "rgba(255,255,255,0.82)",
                }}
              >
                {link.label}
              </Link>
            ))}
          </nav>

          {/* CTA + burger */}
          <div className="flex items-center gap-3">
            <button
              onClick={() => setDemoOpen(true)}
              className="hidden sm:inline-flex items-center gap-2 px-6 py-2.5 text-sm font-semibold rounded-xl transition-all duration-200 hover:opacity-90"
              style={{ background: "linear-gradient(135deg, var(--primary) 0%, #7c3aed 100%)", color: "#fff", boxShadow: "0 2px 12px rgba(0,85,212,0.3)" }}
            >
              Get a Demo
            </button>
            <button
              onClick={() => setMenuOpen(!menuOpen)}
              className="lg:hidden flex flex-col gap-1.25 w-6 cursor-pointer p-0.5"
              aria-label="Toggle menu"
            >
              <span
                className="block h-0.5 rounded transition-all duration-300"
                style={{
                  background: "rgba(255,255,255,0.85)",
                  transform: menuOpen ? "rotate(45deg) translateY(7px)" : undefined,
                }}
              />
              <span
                className="block h-0.5 rounded transition-all duration-300"
                style={{
                  background: "rgba(255,255,255,0.85)",
                  opacity: menuOpen ? 0 : 1,
                  transform: menuOpen ? "scaleX(0)" : undefined,
                }}
              />
              <span
                className="block h-0.5 rounded transition-all duration-300"
                style={{
                  background: "rgba(255,255,255,0.85)",
                  transform: menuOpen ? "rotate(-45deg) translateY(-7px)" : undefined,
                }}
              />
            </button>
          </div>
        </div>
      </div>

      {/* ── Mobile drawer ── */}
      {menuOpen && (
        <div
          className="lg:hidden"
          style={{ background: "var(--dark)", borderTop: "1px solid rgba(255,255,255,0.10)" }}
        >
          <div className="container-xl py-4 flex flex-col gap-1">
            {NAV.map((link) => (
              <Link
                key={link.label}
                href={link.href}
                onClick={() => setMenuOpen(false)}
                className="py-2.5 px-3 text-sm font-medium rounded transition-colors"
                style={{
                  color: pathname === link.href ? "var(--primary)" : "rgba(255,255,255,0.78)",
                }}
              >
                {link.label}
              </Link>
            ))}
            <button
              onClick={() => { setMenuOpen(false); setDemoOpen(true); }}
              className="mt-3 inline-flex px-5 py-2 text-sm font-semibold rounded-full w-fit transition-all duration-200 hover:opacity-90"
              style={{ background: "linear-gradient(135deg, var(--primary) 0%, #7c3aed 100%)", color: "#fff" }}
            >
              Get a Demo
            </button>
          </div>
        </div>
      )}
    </header>
    </>
  );
}

function SyncCoreLogo() {
  return (
    <div className="flex items-center gap-2">
      <svg width="28" height="28" viewBox="0 0 32 32" fill="none">
        <circle cx="16" cy="16" r="13" stroke="#4a8cff" strokeWidth="2" fill="none" />
        <ellipse cx="16" cy="16" rx="7" ry="13" stroke="#4a8cff" strokeWidth="1.5" fill="none" />
        <line x1="3" y1="16" x2="29" y2="16" stroke="#4a8cff" strokeWidth="1.5" />
      </svg>
      <span style={{ fontSize: "19px", fontWeight: 700, letterSpacing: "-0.02em", color: "#fff" }}>
        Sync<span style={{ color: "#4a8cff" }}>Core</span>
      </span>
    </div>
  );
}
